-- 1. Count number of records
SELECT COUNT(*) AS Total_Employees FROM employee;

-- 2. Average value (e.g. score or salary)
SELECT AVG(score) AS Average_Score FROM employee;

-- 3. Highest value
SELECT MAX(score) AS Highest_Score FROM employee;

-- 4. Lowest value
SELECT MIN(score) AS Lowest_Score FROM employee;

-- 5. Total sum of values
SELECT SUM(score) AS Total_Score FROM employee;
